import { useState } from "react";
import axios from "axios";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [feedback, setFeedback] = useState("");

  // handle file upload
  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  // send audio to backend
  const handlePredict = async () => {
    if (!file) {
      alert("Please upload an audio file");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await axios.post(
        "http://127.0.0.1:8000/predict",
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
          },
        }
      );

      setResult(res.data);
    } catch (error) {
      console.error(error);
      alert("Error connecting to backend");
    }
  };

  // send feedback
  const sendFeedback = async () => {
    if (!feedback) {
      alert("Enter feedback");
      return;
    }

    try {
      await axios.post("http://127.0.0.1:8000/feedback", {
        prediction: result.prediction,
        feedback: feedback,
      });

      alert("Feedback saved!");
      setFeedback("");
    } catch (error) {
      console.error(error);
      alert("Error saving feedback");
    }
  };

  return (
    <div style={{ padding: "40px", fontFamily: "Arial" }}>
      <h1>🎧 Cognitive Load Detection System</h1>

      <h3>Upload Lecture Audio</h3>
      <input type="file" accept="audio/*" onChange={handleFileChange} />

      <br /><br />

      <button onClick={handlePredict}>Analyze Lecture</button>

      {result && (
        <div style={{ marginTop: "30px" }}>
          <h2>Prediction: {result.prediction}</h2>

          <h3>Probability:</h3>
          <p>Low: {result.probability.low}</p>
          <p>Medium: {result.probability.medium}</p>
          <p>High: {result.probability.high}</p>

          <h3>Summary:</h3>
          <p>{result.summary}</p>

          <h3>Quiz:</h3>
          <ul>
            {result.quiz.map((q, i) => (
              <li key={i}>{q}</li>
            ))}
          </ul>

          <h3>Give Feedback:</h3>
          <input
            type="text"
            placeholder="Enter feedback"
            value={feedback}
            onChange={(e) => setFeedback(e.target.value)}
          />
          <button onClick={sendFeedback}>Submit Feedback</button>
        </div>
      )}
    </div>
  );
}

export default App;
